const mergedData = $('Normalise the').first()?.json || {};
const metadata = mergedData.metadata || {};

let userClass = metadata.class || "Class_10";
if (!userClass.startsWith("Class_")) {
  const num = userClass.toString().replace(/\D/g, "") || "10";
  userClass = `Class_${num}`;
}

const subject = metadata.subject;  // No default
const board = metadata.board;      // No default

// Build filter dynamically
const mustFilters = [
  { key: "metadata.level", match: { value: userClass } }
];

// Only add board if it exists
if (board) {
  mustFilters.push({ key: "metadata.course", match: { value: board } });
}

// Build should filters
const shouldFilters = [];
if (subject) {
  shouldFilters.push({ key: "metadata.subject", match: { value: subject } });
}

const searchFilter = { must: mustFilters };
if (shouldFilters.length > 0) {
  searchFilter.should = shouldFilters;
}

return {
  json: {
    ...mergedData,
    searchFilter: searchFilter,
    topK: 10
  }
};

