let raw = '';
let detectedSubject = 'Mathematics';  // FIX: Was 'Maths'
let imageUrl = '';

try {
  const docNode = $('Analyze document').first();
  if (docNode && docNode.json) {
    raw = docNode.json.content?.parts?.[0]?.text || 
          docNode.json.text || 
          '';
  }
} catch (e) {
  // Analyze document didn't execute
}

if (!raw || raw.trim() === '') {
  try {
    const agentNode = $('AI Agent1').first();
    if (agentNode && agentNode.json) {
      raw = agentNode.json.output || 
            agentNode.json.text || 
            agentNode.json.content?.parts?.[0]?.text || 
            '';
    }
  } catch (e) {
    console.log('AI Agent1 not executed');
  }
}

try {
  const imageNode = $('Image generation workflow1').first();
  if (imageNode && imageNode.json && imageNode.json.data) {
    const imgData = imageNode.json.data;

    if (typeof imgData === 'string' && 
        imgData.startsWith('https://') && 
        !imgData.includes('<!DOCTYPE') && 
        !imgData.includes('<html')) {
      imageUrl = imgData;
      raw = raw + '\n\n![Generated Image](<' + imageUrl + '>)';
      raw = raw + '\n*⚠️ This image is AI-generated and may contain inaccuracies.*';
    }
  }
} catch (e) {
  console.log('No image generated');
}

try {
  const codeNode = $('Normalise the').first();
  if (codeNode && codeNode.json) {
    detectedSubject = codeNode.json.normalized_subject || 
                      codeNode.json.metadata?.subject || 
                      'Mathematics';  
  }
} catch (e) {
  console.log('Using default subject: Mathematics');  
}

return {
  json: {
    output: raw,
    detectedSubject: detectedSubject,
    imageUrl: imageUrl
  }
};

// Extract User Context - Frontend Only (CLEAN MVP)

const input = $input.first().json;
const body = input.body || {};
const context = body.context || {};

const sessionId = body.chatSessionId || `SESS_${context.userId}_${Date.now()}`;
const userId = context.userId || "unknown";
const message = body.query || "";

// Normalize class: "Class 9" → "Class_9"
const rawCourseLevel = context.courseLevel || "Class 10";
const classNumber = rawCourseLevel.toString().replace(/[^0-9]/g, "") || "10";
const classFormatted = `Class_${classNumber}`;

console.log("=== FRONTEND REQUEST ===");
console.log("User ID:", userId);
console.log("Class:", classFormatted);
console.log("Board:", context.course);

const metadata = {
  class: classFormatted,
  subject: context.subjects?.[0] || null,
  board: context.course || "CBSE",
  chapter_name: null,
  topic: null,
  institute_type: context.educationType || "school",
  level: "intermediate",
  learning_goal: "conceptual understanding"
};

return {
  json: {
    sessionId: sessionId,  
    userId: userId,
    userName: context.displayName || "Student",
    message: message,
    metadata: metadata,
    businessId: context.businessId || null,
    tenantId: context.tenantId || null,
    role: context.role || "student",
    documents: body.documents || []
  }
};

// Get AI-detected subject from Gemini (current input)
const geminiData = $json;
let aiSubject = null;

try {
  aiSubject = 
    geminiData.content?.parts?.[0]?.text ||
    geminiData.text ||
    geminiData[0]?.content?.parts?.[0]?.text;

  if (aiSubject) {
    aiSubject = aiSubject.trim().replace(/\n/g, '').split(/\s+/)[0];
  }
} catch (e) {
  console.log("Error extracting subject:", e);
}

// Allowed subjects - MUST match Qdrant exactly!
const validSubjects = [
  "Mathematics", "Physics", "Chemistry", "Biology",
  "Science", "English", "Social Science", "Hindi"
];

// Normalization map - output MUST match Qdrant metadata.subject
const normalizationMap = {
  "mathematics": "Mathematics", "math": "Mathematics", "maths": "Mathematics",
  "physics": "Physics", "phy": "Physics",
  "chemistry": "Chemistry", "chem": "Chemistry",
  "biology": "Biology", "bio": "Biology",
  "science": "Science", "sci": "Science",
  "english": "English",
  "social": "Social Science", "socialscience": "Social Science",
  "history": "Social Science", "geography": "Social Science",
  "civics": "Social Science", "hindi": "Hindi"
};

let finalSubject = aiSubject;

// Normalize if mapping exists
if (aiSubject && normalizationMap[aiSubject.toLowerCase()]) {
  finalSubject = normalizationMap[aiSubject.toLowerCase()];
}

// Get previous context
let previousData;

// If input has sessionId, it's from Code in JavaScript (doc path)
if ($input.first().json.sessionId) {
  previousData = $input.first().json;
} else {
  // Otherwise get context from Check for Documents1 (no-doc path)
  previousData = $('Check for Documents1').first().json;
}

// Validate subject - use null if invalid (no fallback to Mathematics)
if (!validSubjects.includes(finalSubject)) {
  const currentSubject = previousData.metadata?.subject;
  if (currentSubject && validSubjects.includes(currentSubject)) {
    finalSubject = currentSubject;  // Keep previous subject from context
  } else {
    finalSubject = null;  // No fallback - let vector search decide
  }
}

console.log("Subject:", aiSubject, "→", finalSubject);

return {
  json: {
    ...previousData,
    metadata: {
      ...previousData.metadata,
      subject: finalSubject,  // Can be null
      learning_preferences: "Standard learning style"
    },
    ai_detected_subject: aiSubject,
    normalized_subject: finalSubject
  }
};

// Prepare BINARY data for Gemini Analyze Document node
const context = $input.first().json;

if (!context.documents || context.documents.length === 0) {
  throw new Error('No documents found.');
}

const doc = context.documents[0];
if (!doc || !doc.base64) {
  throw new Error('Document is missing base64 data.');
}

// Extract base64 data (remove data URI prefix if present)
let base64Data = doc.base64 || '';
if (base64Data.includes(',')) {
  base64Data = base64Data.split(',')[1];
}

const mimeType = doc.mimeType || 'image/png';
const fileName = doc.filename || 'document.png';

console.log('=== PREPARING BINARY FOR GEMINI ===');
console.log('MIME Type:', mimeType);
console.log('File Name:', fileName);
console.log('Base64 Length:', base64Data.length);

// Create proper binary data for n8n
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(base64Data, 'base64'),
  fileName,
  mimeType
);

return {
  json: { ...context },
  binary: {
    data: binaryData
  }
};

