// Merge Document Analysis with User Context

// Get Gemini's analysis
const geminiOutput = $json;
const analysisText = 
  geminiOutput.content?.parts?.[0]?.text || 
  geminiOutput.text || 
  geminiOutput || 
  "";

// Get original context from Prepare Document Binary1
const originalContext = $('Prepare Document Binary').first().json;

// Combine message + document analysis for AI Agent
const combinedMessage = originalContext.message 
  ? `${originalContext.message}\n\n[UPLOADED DOCUMENT CONTENT]:\n${analysisText}`
  : `[UPLOADED DOCUMENT CONTENT]:\n${analysisText}`;

console.log("=== DOCUMENT MERGE ===");
console.log("Original message:", originalContext.message);
console.log("Analysis length:", analysisText.length);

return {
  json: {
    ...originalContext,
    message: combinedMessage,
    hasDocument: true,
    documentAnalysis: analysisText,
    metadata: {
      ...originalContext.metadata,
      learning_preferences: originalContext.metadata?.learning_preferences || "Standard learning style"
    }
  }
};

// Add this after Build final json, before Respond to Webhook

const normaliseData = $('Normalise the').first().json;
const searchData = $('Build Dynamic Search2').first().json;
const agentData = $('AI Agent1').first().json;
const finalData = $('Build final json').first().json;

// Get search query from intermediate steps
const searchQuery = agentData.intermediateSteps?.[0]?.action?.toolInput?.input || "";

// Get retrieved content from Qdrant (FULL)
const retrievedContent = agentData.intermediateSteps?.[0]?.observation || "";

// Parse topic names from retrieved content
let topMatchTopics = "";
try {
  const topicMatches = retrievedContent.match(/"topic_name":"([^"]+)"/g);
  if (topicMatches) {
    topMatchTopics = topicMatches
      .slice(0, 5)
      .map(m => m.match(/"topic_name":"([^"]+)"/)[1])
      .join(" | ");
  }
} catch(e) {}

return {
  json: {
    // User Info
    user_id: normaliseData.userId,
    user_name: normaliseData.userName,
    session_id: normaliseData.sessionId,

    // Context
    class: searchData.metadata?.class,
    subject: searchData.metadata?.subject,
    board: searchData.metadata?.board,

    // Query
    user_query: searchData.message,
    has_document: normaliseData.hasDocument || false,

    // Search
    search_query: searchQuery,
    search_filter: JSON.stringify(searchData.searchFilter),

    // Retrieved Content (NEW - FULL)
    top_match_topics: topMatchTopics,
    retrieved_content: retrievedContent,  // ⬅️ FULL content from Qdrant

    // Response
    ai_response: finalData.output?.substring(0, 5000),
    response_length: finalData.output?.length || 0,

    // Image
    image_required: finalData.imageUrl ? true : false,
    image_url: finalData.imageUrl || "",

    // Meta
    timestamp: new Date().toISOString()
  }
};
